mapper.select:
SELECT * FROM gh_accounting_handover_audit
WHERE handover_id = #{handoverId}
ORDER BY step_order ASC, create_time ASC

SELECT a.* FROM gh_accounting_handover_audit a WHERE a.handover_id = #{handoverId} AND a.role_id = #{roleId}
AND a.audit_status = #{auditStatus}
AND a.audit_status = 'pending'
AND ( -- 如果是第一步（step_order = 1），直接可以审核 a.step_order = 1 OR -- 如果不是第一步，需要检查前一步是否已经全部完成 ( a.step_order > 1 AND EXISTS ( -- 前一步必须存在审核记录 SELECT 1 FROM gh_accounting_handover_audit prev WHERE prev.handover_id = a.handover_id AND prev.step_order = a.step_order - 1 ) AND NOT EXISTS ( -- 检查前一步（step_order - 1）是否还有未完成的审核（pending或rejected） SELECT 1 FROM gh_accounting_handover_audit prev WHERE prev.handover_id = a.handover_id AND prev.step_order = a.step_order - 1 AND prev.audit_status != 'approved' ) ) ) ORDER BY a.step_order ASC LIMIT 1
